={{ (() => {
  const codeName = $('📊 Get Scheduled Posts').item.json['File Code Name'];

  // YouTube stats
  const ytItems = $('▶️ YT – Get Stats').item.json?.body?.items || [];
  const ytStats = ytItems[0]?.statistics || {};

  // TikTok stats — find matching video by title/description
  const ttVideos = $('🎵 TikTok – List Videos').item.json?.body?.videos || [];
  const ttMatch = ttVideos.find(v => (v.title || '').toLowerCase().includes(codeName.replace(/-/g, ' '))) || {};

  // IG stats — find matching by caption
  const igMedia = $('📸 IG – Get Media Insights').item.json?.body?.data || [];
  const igMatch = igMedia.find(m => (m.caption || '').toLowerCase().includes(codeName.replace(/-/g, ' '))) || {};
  const igInsights = igMatch.insights?.data || [];
  const igMetric = (name) => (igInsights.find(i => i.name === name)?.values?.[0]?.value || 0);

  // FB stats
  const fbReels = $('📘 FB – Get Reel Insights').item.json?.body?.data || [];
  const fbMatch = fbReels.find(r => (r.description || '').toLowerCase().includes(codeName.replace(/-/g, ' '))) || {};
  const fbInsights = fbMatch.video_insights?.data || [];
  const fbMetric = (name) => (fbInsights.find(i => i.name === name)?.values?.[0]?.value || 0);

  const yt_views = parseInt(ytStats.viewCount || 0);
  const tt_views = parseInt(ttMatch.view_count || 0);
  const ig_views = igMetric('views');
  const fb_views = fbMetric('post_video_views');
  const total_views = yt_views + tt_views + ig_views + fb_views;

  const yt_likes = parseInt(ytStats.likeCount || 0);
  const tt_likes = parseInt(ttMatch.like_count || 0);
  const ig_likes = igMetric('likes');
  const total_likes = yt_likes + tt_likes + ig_likes;

  const tt_shares = parseInt(ttMatch.share_count || 0);
  const ig_shares = igMetric('shares');
  const total_shares = tt_shares + ig_shares;

  const yt_comments = parseInt(ytStats.commentCount || 0);
  const tt_comments = parseInt(ttMatch.comment_count || 0);
  const ig_comments = igMetric('comments');
  const total_comments = yt_comments + tt_comments + ig_comments;

  const top_platform = [['YouTube', yt_views], ['TikTok', tt_views], ['Instagram', ig_views], ['Facebook', fb_views]]
    .sort((a, b) => b[1] - a[1])[0][0];

  const engagement_rate = total_views > 0 ? (((total_likes + total_comments + total_shares) / total_views) * 100).toFixed(2) : '0.00';

  return JSON.stringify({
    file_code_name: codeName,
    date: $('📊 Get Scheduled Posts').item.json['Date'],
    total_views, yt_views, tt_views, ig_views, fb_views,
    total_likes, total_comments, total_shares,
    engagement_rate, top_platform,
    tier: total_views >= 100000 ? '🟢 VIRAL' : total_views >= 10000 ? '🟡 DECENT' : '🔴 LOW'
  });
})() }}

